fix:
public Complex reciprocal() {
    if (isNaN()) {
        return Complex.NaN;
    }

    if (isZero()) {
        return new Complex(Double.POSITIVE_INFINITY, Double.POSITIVE_INFINITY);
    }

    if (getReal() == 0.0 && getImaginaryPart() == 0.0) {
        return Complex.ZERO;
    }

    if (!isFinite()) {
        return new Complex(Double.POSITIVE_INFINITY, Double.POSITIVE_INFINITY);
    }

    if (Math.abs(getReal()) < Math.abs(getImaginaryPart())) {
        double q = getReal() / getImaginaryPart();
        double scale = 1. / (getReal() * q + getImaginaryPart());
        return new Complex(scale * q, -scale);
    } else {
        double q = getImaginaryPart() / getReal();
        double scale = 1. / (getImaginaryPart() * q + getReal());
        return new Complex(scale, -scale * q);
    }
}

